export type ParsedDepositInstruction<
  TProgram extends string = typeof CONTRA_ESCROW_PROGRAM_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    /** Transaction fee payer */
    payer: TAccountMetas[0];
    /** User depositing tokens */
    user: TAccountMetas[1];
    /** Instance PDA to validate */
    instance: TAccountMetas[2];
    /** Token mint being deposited */
    mint: TAccountMetas[3];
    /** AllowedMint PDA to validate mint is allowed */
    allowedMint: TAccountMetas[4];
    /** User's Associated Token Account for this mint */
    userAta: TAccountMetas[5];
    /** Instance's Associated Token Account (escrow) for this mint */
    instanceAta: TAccountMetas[6];
    /** System program */
    systemProgram: TAccountMetas[7];
    /** Token program for the mint */
    tokenProgram: TAccountMetas[8];
    /** Associated Token program */
    associatedTokenProgram: TAccountMetas[9];
    /** Event authority PDA for emitting events */
    eventAuthority: TAccountMetas[10];
    /** Current program for CPI */
    contraEscrowProgram: TAccountMetas[11];
  };
  data: DepositInstructionData;
};

export function parseDepositInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>
): ParsedDepositInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 12) {
    // TODO: Coded error.
    throw new Error('Not enough accounts');
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      payer: getNextAccount(),
      user: getNextAccount(),
      instance: getNextAccount(),
      mint: getNextAccount(),
      allowedMint: getNextAccount(),
      userAta: getNextAccount(),
      instanceAta: getNextAccount(),
      systemProgram: getNextAccount(),
      tokenProgram: getNextAccount(),
      associatedTokenProgram: getNextAccount(),
      eventAuthority: getNextAccount(),
      contraEscrowProgram: getNextAccount(),
    },
    data: getDepositInstructionDataDecoder().decode(instruction.data),
  };
}
